import './Copy.scss';

import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC, MouseEventHandler } from 'react';
import React, { useCallback, useEffect, useRef, useState } from 'react';

import { Icon } from '../Icon';
import { Link } from '../Link';
import { Tooltip } from '../Tooltip';
import type { CopyProps } from './Copy.types';

const copyToClipboard = (text: string): Promise<void> => {
	if (navigator.clipboard?.writeText) {
		return navigator.clipboard.writeText(text);
	}
	return new Promise((resolve, reject) => {
		const textarea = document.createElement('textarea');
		textarea.value = text;
		textarea.style.position = 'fixed';
		textarea.style.opacity = '0';
		document.body.appendChild(textarea);
		textarea.select();
		try {
			document.execCommand('copy');
			resolve();
		} catch (e) {
			reject(e instanceof Error ? e : new Error('Copy failed'));
		} finally {
			document.body.removeChild(textarea);
		}
	});
};

export const Copy: FC<CopyProps> = ({
	value,
	children,
	showTooltip = true,
	tooltipText = 'Копировать',
	tooltipCopiedText = 'Скопировано',
	copiedStateDuration = 3000,
	size = 'medium',
	onCopy,
	onCopyError,
	className,
	dataTestId = 'Copy',
}) => {
	const [copied, setCopied] = useState(false);
	const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

	const clearTimeoutRef = useCallback(() => {
		if (timeoutRef.current) {
			clearTimeout(timeoutRef.current);
			timeoutRef.current = null;
		}
	}, []);

	useEffect(() => {
		return clearTimeoutRef;
	}, [clearTimeoutRef]);

	const handleClick: MouseEventHandler<HTMLElement> = useCallback(
		async event => {
			event.preventDefault();
			clearTimeoutRef();

			try {
				await copyToClipboard(value);
				setCopied(true);
				onCopy?.(value, event as React.MouseEvent<HTMLElement>);
				timeoutRef.current = setTimeout(() => {
					setCopied(false);
					timeoutRef.current = null;
				}, copiedStateDuration);
			} catch (error) {
				onCopyError?.(error instanceof Error ? error : new Error('Copy failed'));
			}
		},
		[value, copiedStateDuration, onCopy, onCopyError, clearTimeoutRef],
	);

	const iconSize = size === 'large' ? 'medium' : 'small';
	const endIcon = copied ? (
		<Icon iconName={Icons.CopyFull} size={iconSize} />
	) : (
		<Icon iconName={Icons.Copy} size={iconSize} />
	);

	const link = (
		<Link
			onClick={handleClick}
			size={size}
			endIcon={endIcon}
			className={classNames('dsb_copy-trigger', className)}
			aria-label={tooltipText}
		>
			{children}
		</Link>
	);

	if (showTooltip) {
		return (
			<span data-testid={dataTestId} className="dsb_copy">
				<Tooltip title={copied ? tooltipCopiedText : tooltipText}>{link}</Tooltip>
			</span>
		);
	}

	return (
		<span data-testid={dataTestId} className="dsb_copy">
			{link}
		</span>
	);
};

Copy.displayName = 'Copy';
